To implement a simple calculator that can add arbitrary size integers using a stack, I'll first define operations for the stack, including push, pop, and peek functions. Then I'll create the main program that will use these stack operations to perform the addition of two large numbers provided as command-line arguments.

Here's the C program for a simple big integer addition calculator using a stack:

```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

// Basic stack structure
struct int_node {
    int value;
    struct int_node *next;
};

// Function to push an element onto the stack
void push(struct int_node **head, int value) {
    struct int_node *new_node = (struct int_node *)malloc(sizeof(struct int_node));
    if (!new_node) {
        fprintf(stderr, "Memory allocation error.\n");
        exit(EXIT_FAILURE);
    }
    new_node->value = value;
    new_node->next = *head;
    *head = new_node;
}

// Function to pop an element from the stack
int pop(struct int_node **head) {
    if (!*head) {
        fprintf(stderr, "Stack underflow.\n");
        exit(EXIT_FAILURE);
    }
    struct int_node *temp = *head;
    int value = temp->value;
    *head = temp->next;
    free(temp);
    return value;
}

// Function to check if the stack is empty
int isEmpty(struct int_node *head) {
    return head == NULL;
}

// Function to free the stack nodes
void freeStack(struct int_node *head) {
    while (head) {
        struct int_node *temp = head;
        head = head->next;
        free(temp);
    }
}

// Function to add two arbitrary size integers using stack
void addBigNumbers(char *num1, char *num2) {
    struct int_node *stack1 = NULL, *stack2 = NULL;

    // Push each digit of the numbers onto their respective stacks
    for (int i = 0; num1[i] != '\0'; i++) {
        push(&stack1, num1[i] - '0');
    }
    for (int i = 0; num2[i] != '\0'; i++) {
        push(&stack2, num2[i] - '0');
    }

    struct int_node *resultStack = NULL;
    int carry = 0;

    // Perform addition
    while (!isEmpty(stack1) || !isEmpty(stack2) || carry != 0) {
        int val1 = isEmpty(stack1) ? 0 : pop(&stack1);
        int val2 = isEmpty(stack2) ? 0 : pop(&stack2);

        int sum = val1 + val2 + carry;
        int num = sum % 10;
        carry = sum / 10;

        push(&resultStack, num);
    }

    // Print the result
    while (!isEmpty(resultStack)) {
        printf("%d", pop(&resultStack));
    }
    printf("\n");

    // Free all stack nodes
    freeStack(stack1);
    freeStack(stack2);
    freeStack(resultStack);
}

int main(int argc, char *argv[]) {
    if (argc != 3) {
        printf("Usage: %s <number1> <number2>\n", argv[0]);
        return EXIT_FAILURE;
    }

    addBigNumbers(argv[1], argv[2]);

    return EXIT_SUCCESS;
}
```

