// Define the stack structure for holding an integer
struct int_node {
    int value;
    struct int_node *next;
};

// Push operation for the stack
void push(struct int_node **head, int value) {
    struct int_node *new_node = malloc(sizeof(struct int_node));
    if (new_node == NULL) {
        fprintf(stderr, "Failed to allocate memory for new stack node.\n");
        exit(EXIT_FAILURE);
    }
    new_node->value = value;
    new_node->next = *head;
    *head = new_node;
}

// Pop operation for the stack
int pop(struct int_node **head) {
    if (*head == NULL) {
        fprintf(stderr, "Attempt to pop from an empty stack.\n");
        exit(EXIT_FAILURE);
    }
    int value = (*head)->value;
    struct int_node *temp = *head;
    *head = (*head)->next;
    free(temp);
    return value;
}

// Check if stack is empty
int is_stack_empty(struct int_node *head) {
    return head == NULL;
}

// Free the stack
void free_stack(struct int_node *head) {
    while (head != NULL) {
        struct int_node *temp = head;
        head = head->next;
        free(temp);
    }
}

// Add two arbitrary-size integers represented as string arguments
void add(char *num1, char *num2) {
    struct int_node *stack1 = NULL, *stack2 = NULL, *result = NULL;

    // Push digits of num1 onto stack1
    for (int i = 0; num1[i] != '\0'; i++) {
        push(&stack1, num1[i] - '0');
    }

    // Push digits of num2 onto stack2
    for (int i = 0; num2[i] != '\0'; i++) {
        push(&stack2, num2[i] - '0');
