    int carry = 0;
    // Iterate over the stacks, adding digits and tracking carry
    while (!is_stack_empty(stack1) || !is_stack_empty(stack2) || carry) {
        int val1 = is_stack_empty(stack1) ? 0 : pop(&stack1);
        int val2 = is_stack_empty(stack2) ? 0 : pop(&stack2);
        int sum = val1 + val2 + carry;
        push(&result, sum % 10);
        carry = sum / 10;
    }

    // Print result
    while (!is_stack_empty(result)) {
        printf("%d", pop(&result));
    }
    printf("\n");

    // Free stacks
    free_stack(stack1);
    free_stack(stack2);
    free_stack(result);
}

int main(int argc, char *argv[]) {
    if (argc != 3) {
        fprintf(stderr, "Usage: %s num1 num2\n", argv[0]);
        return EXIT_FAILURE;
    }

    add(argv[1], argv[2]);
    return EXIT_SUCCESS;
